func GetGOPATH() string {

	gopath := strings.TrimSpace(Get("GOPATH", ""))
	if gopath == "" {
		var err error

		gopath, err = GetRuntimeEnv("GOPATH")
		if err != nil {

			return build.Default.GOPATH
		}
		if gopath == "" {
			return build.Default.GOPATH
		}
		return gopath
	}
	return gopath
}
